import "strconv"

func solve(n int64, x int64) bool {
	s := strconv.FormatInt(n, 10)

	// Convert the digit x into its character representation ('0' through '9')
	targetDigitChar := byte(x + '0')

	// Condition 2 check: It must NOT start with digit x.
	if len(s) > 0 && s[0] == targetDigitChar {
		return false
	}

	// Condition 1 check: It must contain at least one digit x.
	containsX := false
	for i := 0; i < len(s); i++ {
		if s[i] == targetDigitChar {
			containsX = true
			break
		}
	}

	// Return true only if both conditions are met.
	return containsX
}
