func solve(n int64, x int64) bool {
	// Convert n to string
	s := strconv.FormatInt(n, 10)

	// Convert x (digit) to its string representation character
	xStr := strconv.FormatInt(x, 10)
	xChar := xStr[0]

	// Condition 1: It contains at least one digit x
	containsX := strings.ContainsRune(s, rune(xChar))

	// Condition 2: It does not start with the digit x
	// Handle the empty string case defensively, although N >= 0 implies s is never empty.
	startsWithX := false
	if len(s) > 0 {
		if s[0] == xChar {
			startsWithX = true
		}
	}

	// Validity requires (Contains X) AND (NOT Starts with X)
	return containsX && !startsWithX
}
