)

func solve(n int64, x int64) bool {
	// Convert n to its string representation
	s := strconv.FormatInt(n, 10)

	// Convert x to its character representation (byte)
	// Since x is a single digit 0-9, this is safe.
	xByte := byte(x % 10 + '0')

	// Condition 2: Must NOT start with digit x.
	if len(s) > 0 && s[0] == xByte {
		return false
	}

	// Condition 1: Must contain at least one digit x.
	// We check if the byte representation of x exists anywhere in the string s.
	containsX := false
	for i := 0; i < len(s); i++ {
		if s[i] == xByte {
			containsX = true
			break
		}
	}

	if !containsX {
		return false
	}

	// If both conditions are met
	return true
}

